head.script:
/* ★AIcraft guide★    
스크립트 수작업 유의사항
*/


//include KEC_GetGridData(strGridData, colName);
scwin.acnoInfo = "";

scwin.onpageload = function() {
	scwin.OnInitScreen();
};

scwin.onpageunload = function() {}; //계좌번호찾기팝업에서 넘어온 그리드데이터(구분자로 연결된 String)

scwin.cboInquiryGubn_OnItemChanged = function(e) {
    //여기에 구현코드를 삽입하세요.
    //	1.콤보에 key-value 로 
    //   '1'- 계약응당일 
    //   '2'- 부담금납입을 select item에 등록합니다. 
    //	2. 화면 ONLOAD시 조회구분이 계약응당일('1')로 셋팅한다. 
    //	3. 계약응당일('1')이 선택되면 자동으로 패널에 'KEC04M8AA01'화면을 로드 합니다. 
    //	4. 부담금납입('2')이 선택되면 자동으로 패널에 'KEC04M8AA02'화면을 로드 합니다. 
    if (cboInquiryGubn.getValue() == "1") {
        $c.iz.data.commonButtonEnable(0, true); //실행
        Panel1.setSrc("KEC04M8AA01.xml");
    } else {
        $c.iz.data.commonButtonEnable(0, false); //실행

        Panel1.setSrc("KEC04M8AA02.xml");
    }
};

scwin.AccountID_OnValidate = async function(info) {
    //여기에 구현코드를 삽입하세요.
    if (AccountID.getValue().length == 14) {
        if ($c.com.kec.CheckAccountNo(AccountID.getValue()) == false) {
            AccountID.setValue("");
            return false;
        }
        $c.iz.tran.setTranID("KEC04M8A41");
        await $c.iz.tran.ASend();
    }
};

scwin.OnInitScreen = function() {
    //여기에 구현코드를 삽입하세요.
    fldStartingYymmdd.setValue($c.user.getUserProfile('tranBaseYmd'));
};

scwin.OnSendKey = async function() {
    //여기에 구현코드를 삽입하세요.

    var inquiryGubn = cboInquiryGubn.getValue();
    var startingYymmdd = fldStartingYymmdd.getValue();
    var paymentScheduleYymmdd = "";
    var paymentScheduledBurdenAmount = "";
    if (inquiryGubn == "1") {
        if (startingYymmdd > $c.user.getUserProfile('tranBaseYmd')) {
            $c.iz.data.message("조회기준일자를  확인해 주십시요. 미래일자로는 조회가 불가합니다.");
            return;
        }
    } else if (inquiryGubn == "2") {
        paymentScheduleYymmdd = $c.iz.data.getChildData("fldPaymentScheduledYymmdd.Data", "Panel1");
        paymentScheduledBurdenAmount = $c.iz.data.getChildData("fldPaymentScheduledBurdenAmount.Data", "Panel1");
        if (paymentScheduleYymmdd == "") {
            $c.iz.data.message("납입예정일자 항목에 값이 입력되지 않았습니다.");
            return;
        } else if (fldPaymentScheduledBurdenAmount.Data == "") {
            $c.iz.data.message("납입예정부담금 항목에 값이 입력되지 않았습니다.");
            return;
        } else if (paymentScheduleYymmdd == "" && fldPaymentScheduledBurdenAmount.Data == "") {
            $c.iz.data.message("납입예정부담금 항목과 납입예정일자 항목에 값이 입력되지 않았습니다.");
            return;
        }
        if (paymentScheduleYymmdd < $c.user.getUserProfile('tranBaseYmd')) {
            $c.iz.data.message("납입예정일자를 확인해 주십시요. 과거년월일로는 조회가 불가합니다.");
            return;
        }
        if (paymentScheduleYymmdd >= fldManagementInstitutionAnnualDate.Data) {
            $c.iz.data.message("납입예정일자를 확인해 주십시요. 운용관리계약 응당일이전 날짜만 조회가 가능합니다.");
            return;
        }
        if (paymentScheduleYymmdd >= fldAssetManagementAnnualDate.Data) {
            $c.iz.data.message("납입예정일자를 확인해 주십시요. 자산관리계약 응당일이전 날짜만 조회가 가능합니다.");
            return;
        }
        if (fldPaymentScheduledBurdenAmount.Data == "0") {
            $c.iz.data.message("0원 보다 큰 금액을 입력해 주십시요.");
            return;
        }
    }
    $c.iz.tran.setTranID("KEC04M8A42");
    await $c.iz.tran.ASend();
};

scwin.Button3_OnClick = function(e) {
    //여기에 구현코드를 삽입하세요.

    //사용자조회	KEC04U21001
    //운용관리의 기업형 IRA 사용자정보를 조회한다. 
    //sendData : 없음
    //getData  : 고객번호(fldCustomNumber_g) -> 다계좌입금 화면의 사용자고객번호(fldUserNumber)
    //              고객명 (fldCustomName_g)  -> 다계좌입금 화면의 사용자고객명(fldUserName)




    Link.lnkfldScrNo = "KEC04M8A000";
    Link.lnkValueCheck = "1";
    $c.iz.screen.popup("KEC04U21001", "DATALINK");
    scwin.acnoInfo = Link.lnkAcnoInfo;
    fldCustomerName.setValue($c.com.kec.GetGridData(scwin.acnoInfo, "fldCustomName_g"));
    AccountID.setValue($c.com.kec.GetGridData(scwin.acnoInfo, "fldAccountNumber_g"));
    fldSystemKindDistinctionName.setValue($c.com.kec.GetGridData(scwin.acnoInfo, "fldContractClassName_g"));
    fldSystemKindDistinction.setValue($c.com.kec.GetGridData(scwin.acnoInfo, "fldContractClass_g"));
    //fldSystemKindDistinctionName.Data		= KEC_GetGridData(acnoInfo, "fldContractClassName_g"); 
    scwin.AccountID_OnValidate();
};
